public class LoanCalculator {
    public static void main(String[] args) {
        // Applicant data
        String name = "Vikram Mehta";
        double annualIncome = 750000.0;
        int age = 32;
        int creditScore = 720;
        double currentDebt = 200000.0;
        String employmentStatus = "Employed";

        // Calculate ratio
        double debtToIncomeRatio = currentDebt / annualIncome;

        // Individual checks
        boolean incomeOK = annualIncome >= 500000;
        boolean ageOK = age >= 21 && age <= 60;
        boolean creditOK = creditScore >= 650;
        boolean debtRatioOK = debtToIncomeRatio < 0.4;
        boolean employmentOK = employmentStatus.equals("Employed") || employmentStatus.equals("Self-Employed");

        // Overall qualification
        boolean qualifies = incomeOK && ageOK && creditOK && debtRatioOK && employmentOK;

        // Output
        System.out.println("=========================================");
        System.out.println("         LOAN PRE-QUALIFICATION");
        System.out.println("=========================================");
        System.out.println("Applicant: " + name);
        System.out.println("Annual Income: " + annualIncome);
        System.out.println("Age: " + age);
        System.out.println("Credit Score: " + creditScore);
        System.out.println("Debt: " + currentDebt);
        System.out.println("Debt-to-Income Ratio: " + debtToIncomeRatio);
        System.out.println("Employment: " + employmentStatus);
        System.out.println("-----------------------------------------");
        System.out.println("Income OK: " + incomeOK);
        System.out.println("Age OK: " + ageOK);
        System.out.println("Credit OK: " + creditOK);
        System.out.println("Debt Ratio OK: " + debtRatioOK);
        System.out.println("Employment OK: " + employmentOK);
        System.out.println("-----------------------------------------");
        System.out.println("QUALIFIES FOR LOAN: " + qualifies);
        System.out.println("=========================================");
    }
}
